  const projectMemory = await buildProjectMemory(dossierId)

  const n8nResult = await invokeN8nPole(
    {
      poleCode: pole.code,
      managerName: pole.managerName,
      systemPrompt: pole.systemPrompt,
      userMessage,
      projectMemory,
      dossierId,
      labContext: currentLab,
